import "dotenv/config";

import { createServer as createHttpServer, type Server } from "node:http";

import cors from "cors";
import express from "express";
import helmet from "helmet";

import { authRouter } from "./api/auth";
import { contentRouter } from "./api/content";
import { healthRouter } from "./api/health";
import { notificationsRouter } from "./api/notifications";
import { reportsRouter } from "./api/reports";
import { todosRouter } from "./api/todos";
import { closeDatabasePool, verifyDatabaseConnection } from "./lib/db";

const DEFAULT_API_PORT = 3001;

function getApiPort(): number {
  const portValue =
    process.env.API_PORT ?? process.env.PORT ?? `${DEFAULT_API_PORT}`;
  const port = Number.parseInt(portValue, 10);

  if (Number.isNaN(port) || port < 1) {
    throw new Error("API_PORT must be a positive integer.");
  }

  return port;
}

function getAllowedOrigins(): string[] {
  const originValues = [
    process.env.NEXT_PUBLIC_APP_URL?.trim(),
    process.env.API_BASE_URL?.trim(),
  ].filter((value): value is string => Boolean(value));

  return [...new Set(originValues)];
}

export function createServer() {
  const app = express();
  const allowedOrigins = getAllowedOrigins();

  app.disable("x-powered-by");
  app.use(helmet());
  app.use(
    cors({
      credentials: true,
      origin(origin, callback) {
        if (
          !origin ||
          allowedOrigins.length === 0 ||
          allowedOrigins.includes(origin)
        ) {
          callback(null, true);
          return;
        }

        callback(new Error("Origin not allowed by CORS."));
      },
    }),
  );
  app.use(express.json());

  app.use("/api", healthRouter);
  app.use("/api/auth", authRouter);
  app.use("/api/content", contentRouter);
  app.use("/api/notifications", notificationsRouter);
  app.use("/api/reports", reportsRouter);
  app.use("/api/todos", todosRouter);

  return app;
}

async function listen(server: Server, port: number): Promise<void> {
  await new Promise<void>((resolve, reject) => {
    server.once("listening", resolve);
    server.once("error", reject);
    server.listen(port);
  });
}

async function closeServer(server: Server): Promise<void> {
  await new Promise<void>((resolve, reject) => {
    server.close((error) => {
      if (error) {
        reject(error);
        return;
      }

      resolve();
    });
  });
}

export async function startServer(): Promise<Server> {
  const port = getApiPort();
  const app = createServer();
  const server = createHttpServer(app);

  try {
    await verifyDatabaseConnection();
    console.log("Database connection verified");
  } catch (error) {
    console.warn("Database connection unavailable during startup", error);
  }

  await listen(server, port);

  console.log(`API server listening on port ${port}`);

  let isShuttingDown = false;

  const shutdown = async (signal: NodeJS.Signals) => {
    if (isShuttingDown) {
      return;
    }

    isShuttingDown = true;
    console.log(`Received ${signal}, shutting down API server`);

    try {
      await closeServer(server);
      await closeDatabasePool();
    } catch (error) {
      console.error("Failed to shut down API server cleanly", error);
      process.exitCode = 1;
    } finally {
      process.exit();
    }
  };

  process.once("SIGINT", () => {
    void shutdown("SIGINT");
  });

  process.once("SIGTERM", () => {
    void shutdown("SIGTERM");
  });

  return server;
}

void startServer().catch(async (error) => {
  console.error("Failed to start API server", error);

  try {
    await closeDatabasePool();
  } finally {
    process.exit(1);
  }
});

